// CLX Video Ready v1 — Normalize Tavus callback payload
// Tavus sends different body shapes across endpoints; handle the
// common fields with best-effort extraction. Non-terminal statuses
// ('queued','generating') are ignored.

const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const data = body.data || body;

const status = String(data.status || body.status || 'unknown').toLowerCase();
if (status !== 'ready' && status !== 'completed' && status !== 'failed' && status !== 'error') {
  return { json: { _skip: true, skip_reason: 'non_terminal_status', status } };
}

const video_id = data.video_id || data.id || body.video_id || body.id || null;
const video_url = data.hosted_url || data.download_url || data.video_url || null;
const thumbnail_url = data.thumbnail_url || data.thumbnail || null;
const duration = Number(data.duration || data.duration_seconds || body.duration || 0) || null;
const cost = Number(data.total_cost || data.cost || 0) || null;

if (!video_id) {
  return { json: { _skip: true, skip_reason: 'missing_video_id' } };
}

const terminal_failed = (status === 'failed' || status === 'error');

return {
  json: {
    video_id,
    video_url,
    thumbnail_url,
    duration_sec: duration,
    cost_usd: cost,
    terminal_failed,
    status
  }
};

// CLX Video Ready v1 — Correlate + merge
// Joins the normalized callback payload to the lead row it originated
// from. A missing match logs VIDEO_RESULT_NO_MATCH and short-circuits.
// On terminal_failed we still produce an update body so the lead
// reflects the failure; downstream IF branch logs VIDEO_DELIVERY_FAILED.

const norm = $('Normalize Payload').first().json;
const rows = $input.item.json;
const lead = Array.isArray(rows) ? rows[0] : rows;

if (!lead || !lead.id) {
  return { json: { _skip: true, skip_reason: 'lead_not_found_for_video_id', video_id: norm.video_id } };
}

return {
  json: {
    ...lead,
    video_url: norm.video_url,
    thumbnail_url: norm.thumbnail_url,
    duration_sec: norm.duration_sec,
    cost_usd: norm.cost_usd,
    terminal_failed: norm.terminal_failed === true,
    callback_status: norm.status
  }
};

// CLX Video Ready v1 — Build video-embedded email HTML
// Inline clickable thumbnail (play overlay) linking to the hosted Tavus
// URL. Peer-advisor copy leaning on the video as the hook. Calendly CTA
// pulled from client.calendly_link (fallback to a safe generic link).

const lead = $input.item.json;
const client = lead.clients || {};

const firstName = (lead.full_name || '').split(' ')[0] || 'there';
const company = lead.company || 'your team';
const videoUrl = lead.video_url || '#';
const thumbUrl = lead.thumbnail_url || 'https://via.placeholder.com/600x340.png?text=Watch+60+seconds';
const calendly = client.calendly_link || 'https://calendly.com/crystallux/intro';

const subject = 'Quick 60-second video for ' + company;

const htmlBody = [
  '<div style="font-family:system-ui,Segoe UI,Arial,sans-serif;max-width:620px;margin:0 auto;color:#1a202c;line-height:1.5;">',
  '  <p>Hi ' + firstName + ',</p>',
  '  <p>I recorded a quick 60-second video for you and the team at ' + company + ' — easier to explain this way than in a wall of text:</p>',
  '  <p style="text-align:center;margin:24px 0;">',
  '    <a href="' + videoUrl + '" target="_blank" style="display:inline-block;position:relative;">',
  '      <img src="' + thumbUrl + '" alt="Watch video" width="600" style="display:block;border-radius:8px;border:1px solid #e2e8f0;max-width:100%;height:auto;" />',
  '      <span style="position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);background:rgba(0,0,0,0.65);color:#fff;padding:14px 22px;border-radius:50px;font-size:16px;font-weight:600;">\u25B6&nbsp; Play video (60s)</span>',
  '    </a>',
  '  </p>',
  '  <p>If any of this resonates, I\'d love 20 minutes to walk through how it would work specifically at ' + company + '. Here\'s my calendar:</p>',
  '  <p style="text-align:center;margin:20px 0;">',
  '    <a href="' + calendly + '" target="_blank" style="display:inline-block;background:#2563eb;color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;">Book 20 minutes</a>',
  '  </p>',
  '  <p>Talk soon,<br/>Mary</p>',
  '  <hr style="border:none;border-top:1px solid #e2e8f0;margin:24px 0;" />',
  '  <p style="font-size:12px;color:#718096;">Mary Akintunde, Crystallux \u2014 <a href="https://crystallux.org" style="color:#718096;">crystallux.org</a></p>',
  '</div>'
].join('\n');

return {
  json: {
    ...lead,
    video_email_subject: subject,
    video_email_body: htmlBody
  }
};

// Build Gmail API raw message — RFC 2822 + base64url
// Mirrors clx-outreach-sender-v2 'Build Gmail Raw Message' exactly.
// TESTING MODE — remove before production

const data = $input.item.json;
const to = 'adesholaakintunde+clxtest@gmail.com'; // TESTING MODE — remove before production
const subject = data.video_email_subject || '';
const htmlBody = data.video_email_body || '';
const fromName = 'Mary Akintunde (Crystallux)';
const fromEmail = 'info@crystallux.org';

const encodedSubject = '=?UTF-8?B?' + Buffer.from(subject, 'utf8').toString('base64') + '?=';

const mime = [
  'From: "' + fromName + '" <' + fromEmail + '>',
  'To: ' + to,
  'Subject: ' + encodedSubject,
  'MIME-Version: 1.0',
  'Content-Type: text/html; charset=utf-8',
  'Content-Transfer-Encoding: 7bit',
  '',
  htmlBody
].join('\r\n');

const raw = Buffer.from(mime, 'utf8').toString('base64')
  .replace(/\+/g, '-')
  .replace(/\//g, '_')
  .replace(/=+$/, '');

return { json: { ...data, gmail_raw: raw, to_address: to } };

// CLX Video Ready v1 — Handle Gmail send result
// Captures Gmail API id/threadId on success; extracts error message on
// failure for the downstream scan_errors log.

const incoming = $input.item.json || {};
const lead = $('Build Gmail Raw Message').first().json;
const errorObj = incoming.error || $input.item.error;
const sendOk = !errorObj && !!(incoming.id || incoming.threadId || incoming.messageId);

return {
  json: {
    ...lead,
    gmail_ok: sendOk,
    gmail_message_id: incoming.id || incoming.messageId || null,
    gmail_thread_id: incoming.threadId || null,
    gmail_error: errorObj ? (errorObj.message || (typeof errorObj === 'string' ? errorObj : JSON.stringify(errorObj))) : null
  }
};

// CLX Video Ready v1 — Prep lead update
// On successful send: video_status='delivered', video_delivered_at=now,
// lead_status='Video Sent'. On failure: video_status='ready' (video did
// render, just couldn't be emailed) so a retry flow can pick it up.

const item = $input.item.json;

const fields = {
  video_url: item.video_url || null,
  video_status: item.gmail_ok ? 'delivered' : 'ready'
};
if (item.gmail_ok) {
  fields.video_delivered_at = new Date().toISOString();
  fields.lead_status = 'Video Sent';
  fields.last_channel_attempted = 'video';
  fields.last_channel_attempted_at = new Date().toISOString();
}

const body = { p_lead_id: item.id, p_fields: fields };

return { json: { ...item, rpc_body: JSON.stringify(body) } };
